bot.onText(/\/removeadmin (.+)/, async (msg, match) => {
    try {
        if (!isPrimaryAdmin(msg.from.id)) {
            return bot.sendMessage(msg.chat.id, 'вЭМ Only primary admin can remove admins!');
        }
        
        const adminId = match[1];
        if (adminId === ADMIN_ID) {
            return bot.sendMessage(msg.chat.id, 'вЭМ Cannot remove primary admin!');
        }
        
        try {
            const result = await pool.query('DELETE FROM admins WHERE admin_id = $1 AND is_primary = FALSE', [adminId]);
            
            if (result.rowCount > 0) {
                await bot.sendMessage(msg.chat.id, `вЬЕ Admin ${adminId} removed successfully!`);
            } else {
                await bot.sendMessage(msg.chat.id, 'вЭМ Admin not found or is primary admin!');
            }
        } catch (error) {
            console.error('Error removing admin:', error);
            await bot.sendMessage(msg.chat.id, 'вЭМ Error removing admin!');
        }
    } catch (error) {
        console.error('Error in /removeadmin:', error.message);
    }
});

